  "silo-tanktransport": {"intro":"Silo- und Tanktransporte steuern mit ARGONAUT OS Aufträge, Fahrzeuge, Reinigungsnachweise und Abrechnung aus einem System. Sie planen Transporte samt Vorprodukt und rechnen Kunden direkt ab. Der Betrieb bleibt DSGVO-konform auf deutschem Server.","faq":[{"q":"Kann ich Transporte samt Produkt und Vorladung planen?","a":"Ja, zu jedem Auftrag hinterlegen Sie Produkt, Vorladung und Reinigungsbedarf. So vermeiden Sie Verwechslungen und Kontaminationen."},{"q":"Lassen sich Reinigungsnachweise dokumentieren?","a":"Ja, Reinigungen und Nachweise erfassen Sie je Fahrzeug und Auftrag nachvollziehbar. Das ist bei Kontrollen und Kundennachfragen wertvoll."},{"q":"Behalte ich Fahrzeuge und Fahrer im Blick?","a":"Ja, Fahrzeuge und Fahrer teilen Sie je Auftrag ein und vermeiden Doppelbelegungen. So sehen Sie, wer welchen Transport übernimmt."},{"q":"Ist das auch für einen kleinen Fuhrpark geeignet?","a":"Ja, gerade kleinere Betriebe profitieren, weil Planung, Nachweise und Abrechnung zusammenlaufen. Das ersetzt mehrere Tools."}]},
  "werttransport-geldlogistik": {"intro":"Werttransport und Geldlogistik verwalten mit ARGONAUT OS Aufträge, Touren, Personal und Abrechnung in einem System. Sie planen Fahrten samt Nachweisen und rechnen Kunden direkt ab. Alles läuft DSGVO-konform auf deutschen Servern.","faq":[{"q":"Kann ich Touren und Objekte sicher planen?","a":"Ja, zu jedem Kunden hinterlegen Sie Objekte, Rhythmus und Tour. So sind wiederkehrende Fahrten strukturiert und nachvollziehbar geplant."},{"q":"Lassen sich Übergaben und Nachweise dokumentieren?","a":"Ja, Übergaben und Vorgänge halten Sie je Auftrag nachvollziehbar fest. Das schafft Klarheit bei Rückfragen und Nachweisen."},{"q":"Behalte ich Personal und Einsätze im Blick?","a":"Ja, Personaleinsätze je Tour planen und dokumentieren Sie zentral. So sehen Sie, wer wann welchen Einsatz übernimmt."},{"q":"Wie aufwendig ist die Einführung?","a":"Die Grundeinrichtung gelingt in wenigen Tagen, Kunden und Abläufe übernehmen Sie schrittweise. Sie starten mit den wichtigsten Prozessen."}]},
  "schienengueterverkehr": {"intro":"Im Schienengüterverkehr verbindet ARGONAUT OS Transportaufträge, Waggons, Termine und Abrechnung in einem System. Sie planen Ladungen und Umläufe und rechnen Kunden direkt ab. Der Betrieb bleibt DSGVO-konform auf deutschem Server.","faq":[{"q":"Kann ich Transportaufträge und Waggons verwalten?","a":"Ja, zu jedem Auftrag hinterlegen Sie Ladung, Waggons und Termine. So behalten Sie Umläufe und Kapazitäten im Blick."},{"q":"Lässt sich der Status von Sendungen verfolgen?","a":"Ja, zu jeder Sendung sehen Sie Status und Zuordnung, sodass Sie Kundenanfragen schnell beantworten. Das schafft Verlässlichkeit."},{"q":"Wie rechne ich Transportleistungen ab?","a":"Leistungen und Mengen erfassen Sie je Auftrag und rechnen sie direkt ab. Die Kundenhistorie erleichtert wiederkehrende Relationen."},{"q":"Wie schnell bin ich einsatzbereit?","a":"Die Grundeinrichtung gelingt in wenigen Tagen, Kunden und Abläufe übernehmen Sie schrittweise. Sie starten mit den wichtigsten Prozessen."}]},
  "zoll-aussenhandelslogistik": {"intro":"Zoll- und Außenhandelslogistik steuern mit ARGONAUT OS Vorgänge, Dokumente, Fristen und Abrechnung aus einem System. Sie behalten jede Abfertigung samt Unterlagen im Blick und rechnen Kunden direkt ab. Alles läuft DSGVO-konform auf deutschen Servern.","faq":[{"q":"Kann ich Zollvorgänge samt Unterlagen verwalten?","a":"Ja, zu jedem Vorgang hinterlegen Sie Sendung, Dokumente und Fristen. So sind alle Unterlagen zur Abfertigung zentral griffbereit."},{"q":"Behalte ich Fristen und Termine im Blick?","a":"Ja, Fristen und Termine sind je Vorgang einsehbar, sodass nichts übersehen wird. Das reduziert das Risiko von Verzögerungen."},{"q":"Wie rechne ich meine Dienstleistungen ab?","a":"Leistungen und Auslagen erfassen Sie je Vorgang und rechnen sie direkt ab. Die Historie macht Ihre Leistungen für Kunden transparent."},{"q":"Ist das auch für einen kleinen Dienstleister sinnvoll?","a":"Ja, gerade kleinere Dienstleister sparen Zeit, weil Vorgänge, Dokumente und Abrechnung zusammenlaufen. Das ersetzt mehrere Tools."}]},
  "lebendtier-tiertransport": {"intro":"Lebendtier- und Tiertransporte verwalten mit ARGONAUT OS Aufträge, Fahrzeuge, Nachweise und Abrechnung in einem System. Sie planen Fahrten samt Vorgaben und rechnen Kunden direkt ab. Der Betrieb bleibt DSGVO-konform auf deutschem Server.","faq":[{"q":"Kann ich Transporte samt Tierart und Vorgaben planen?","a":"Ja, zu jedem Auftrag hinterlegen Sie Tierart, Anzahl und besondere Vorgaben. So sind Fahrzeug und Fahrer passend vorbereitet."},{"q":"Lassen sich Nachweise und Papiere zuordnen?","a":"Ja, Begleitpapiere und Vermerke ordnen Sie direkt dem Transport zu. So sind alle Unterlagen bei Kontrollen zentral griffbereit."},{"q":"Behalte ich Fahrzeuge und Fahrer im Blick?","a":"Ja, Fahrzeuge und Fahrer teilen Sie je Auftrag ein und vermeiden Doppelbelegungen. So sehen Sie, wer welchen Transport übernimmt."},{"q":"Wie schnell bin ich startklar?","a":"Die Grundeinrichtung gelingt in wenigen Tagen, Kunden und Abläufe übernehmen Sie schrittweise. Sie starten mit den wichtigsten Prozessen."}]},
  "busreise-reisebusverkehr": {"intro":"Busreise- und Reisebusverkehr steuern mit ARGONAUT OS Buchungen, Fahrten, Fahrer und Abrechnung aus einem System. Sie planen Reisen samt Teilnehmern und rechnen Kunden direkt ab. Alles läuft DSGVO-konform auf deutschen Servern.","faq":[{"q":"Kann ich Reisen und Fahrten mit Teilnehmern planen?","a":"Ja, zu jeder Fahrt hinterlegen Sie Route, Termine und Teilnehmer. So behalten Sie Auslastung und Ablauf jeder Reise im Blick."},{"q":"Lassen sich Fahrer und Busse disponieren?","a":"Ja, Fahrer und Fahrzeuge teilen Sie je Fahrt ein und vermeiden Doppelbelegungen. So sehen Sie, welcher Bus wann unterwegs ist."},{"q":"Wie rechne ich Reisen und Zusatzleistungen ab?","a":"Reisepreise und Zusatzleistungen erfassen Sie je Buchung und rechnen sie direkt ab. Die Kundenhistorie erleichtert wiederkehrende Gruppen."},{"q":"Ist das auch für einen kleinen Betrieb geeignet?","a":"Ja, gerade kleinere Betriebe profitieren, weil Buchung, Disposition und Abrechnung zusammenlaufen. Das ersetzt mehrere Tools."}]},
  "taxi-mietwagenunternehmen": {"intro":"Taxi- und Mietwagenunternehmen verwalten mit ARGONAUT OS Fahrten, Fahrer, Fahrzeuge und Abrechnung in einem System. Sie disponieren Aufträge und rechnen Privat- wie Firmenkunden direkt ab. Der Betrieb bleibt DSGVO-konform auf deutschem Server.","faq":[{"q":"Kann ich Fahrten schnell aufnehmen und zuteilen?","a":"Ja, eingehende Aufträge erfassen Sie zügig und weisen sie freien Fahrern zu. So reagieren Sie auch bei kurzfristigen Fahrten sicher."},{"q":"Lassen sich Fahrer und Fahrzeuge verwalten?","a":"Ja, Fahrer und Fahrzeuge teilen Sie je Schicht und Auftrag ein. So behalten Sie den Überblick über Ihren Fuhrpark."},{"q":"Wie rechne ich Firmenkunden und Rechnungsfahrten ab?","a":"Firmenkunden mit eigenen Konditionen verwalten Sie zentral und rechnen direkt ab. Sammelrechnungen machen wiederkehrende Fahrten nachvollziehbar."},{"q":"Ist das auch für einen kleinen Fuhrpark sinnvoll?","a":"Ja, gerade kleinere Unternehmen sparen Zeit, weil Disposition und Abrechnung zusammenlaufen. Das ersetzt mehrere Einzellösungen."}]},
